mapper.delete:
DELETE FROM fx_bar_load
WHERE symbol = #{symbol}
  AND bar_date_time = (
    SELECT max_dt FROM (
      SELECT MAX(bar_date_time) AS max_dt FROM fx_bar_load WHERE symbol = #{symbol}
    ) AS t
  )

DELETE FROM fx_bar_load_sma
WHERE symbol = #{symbol}
  AND bar_date_time = (
    SELECT max_dt FROM (
      SELECT MAX(bar_date_time) AS max_dt FROM fx_bar_load_sma WHERE symbol = #{symbol}
    ) AS t
  )

DELETE FROM fx_bar_load_rsi
WHERE symbol = #{symbol}
  AND bar_date_time = (
    SELECT max_dt FROM (
      SELECT MAX(bar_date_time) AS max_dt FROM fx_bar_load_rsi WHERE symbol = #{symbol}
    ) AS t
  )

mapper.select:
SELECT DATE_FORMAT(MAX(bar_date_time), '%Y-%m-%d %H:%i:%s')
FROM fx_bar_load
WHERE symbol = #{symbol}
